    // leftMax[i] stores the maximum value of nums[0...i-1]
    const leftMax = new Array(n);
    leftMax[0] = -1; // Since all elements are >= 1
    for (let i = 1; i < n; i++) {
        leftMax[i] = Math.max(leftMax[i - 1], nums[i - 1]);
    }

