    for (let i = 0; i < n; i++) {
        // Condition 1: Strictly greater than all elements to its left
        const isGreaterLeft = nums[i] > leftMax[i];

        // Condition 2: Strictly greater than all elements to its right
        const isGreaterRight = nums[i] > rightMax[i];

        // An element is effective if AT LEAST ONE condition is met
        if (isGreaterLeft || isGreaterRight) {
